import React, { useEffect, useState } from 'react'
import styled from 'styled-components'
import {getSingleDesinger} from '../WebAPI'


const DesignerIntroWrapper = styled.div `
width:80%;
${props => props.isIntroSectionOpen ? 'height:auto' : 'height:500px'};
border:1px solid rgb(180, 180, 180);
margin:60px auto;
border-radius:3px;
overflow:hidden;
position:relative;
`

const Banner = styled.div `
height:200px;
background-image:url('${props => props.banner ? props.banner : props.banner}');
background-size:cover;
background-position:center;
`

const Body = styled.div `
height:300px;
padding:0 18%;
margin:30px 0;
line-height:30px;
font-size:1rem;
box-sizing:border-box;
overflow:hidden;
`

const HideSection = styled.div `
position:absolute;
margin-top:400px;
height:100px;
background:linear-gradient(to top, white, transparent);
width:100%;
${props => props.isIntroSectionOpen ? 'display:none' : 'display:flex'};
padding:20px 40px;
box-sizing:border-box;
justify-content:flex-end;
align-items:flex-end;

`

const ReadMore =styled.div `
width:100px;
height:30px;
background-color:white;
font-size:0.7rem;
font-weight:800;
color:rgb(70, 70, 70);
border-radius:5px;
line-height:30px;
text-align:center;
border:1px solid rgb(70, 70, 70);
transition:all 0.2s ease-in;
&:hover {
	cursor:pointer;
	color:white;
	background-color:rgb(70, 70, 70);
}
`

const ReadLess = styled(ReadMore) `
margin-left:85%;
margin-bottom:30px;
${props => props.isIntroSectionOpen ? null : 'display:none'};
`

const BrandAvatar = styled.div `
height:140px;
width:140px;
margin-top:135px;
margin-left:40px;
border-radius:50%;
position:absolute;
background-image:url('${props => props.logo ? props.logo : null}');
background-size:cover;
background-position:center;
filter: drop-shadow(0px 10px 10px rgba(70, 70, 70,.2));
`

export default function DesignerIntroSection ({id}) {
	const [isIntroSectionOpen, setIsIntroSectionOpen] = useState(false)
	const [desingerInfo, setDesingerInfo] = useState({})

	useEffect(() => {
		getSingleDesinger(id, setDesingerInfo)
	},[])

	const onReadMoreClick = () => {
		setIsIntroSectionOpen(!isIntroSectionOpen)
	}

	return (
		<DesignerIntroWrapper isIntroSectionOpen={isIntroSectionOpen}>
			<BrandAvatar logo={desingerInfo.logo}/>
			{console.log(desingerInfo.logo)}
			<HideSection isIntroSectionOpen={isIntroSectionOpen}>
				<ReadMore onClick={onReadMoreClick}>SHOW MORE</ReadMore>
			</HideSection>
			<Banner banner={desingerInfo.banner}></Banner>
			<Body>
				{desingerInfo.Inroduction}
			</Body>
			<ReadLess onClick={onReadMoreClick} isIntroSectionOpen={isIntroSectionOpen}>SHOW LESS</ReadLess>
		</DesignerIntroWrapper>
	)
}
